369 <script>
370 /* ── Data: all rows as JS array, never rendered all at once ── */
371 var DATA = {rows_json};
372 /* columns: [mk,ft,fn_lower,txt,display_name,grid,mapnum,mapname,year,conf_str,conf_color] */
373 var PAGE_SIZE = 2000;
374 var filteredData = [];
375 
376 /* ── Helpers ──────────────────────────────────────────────────────── */
377 function getChecked() {{
378   return Array.from(document.querySelectorAll('.map-cb:checked')).map(function(cb) {{ return cb.value; }});
379 }}
380 function esc(s) {{
381   return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
382 }}
383 
384 /* ── Render: only PAGE_SIZE rows go to DOM ───────────────────────── */
385 function renderTable() {{
386   var slice = filteredData.slice(0, PAGE_SIZE);
387   var h = '';
388   for (var i = 0; i < slice.length; i++) {{
389     var r = slice[i];
390     h += '<tr><td><strong>' + esc(r[4]) + '</strong></td>'
391        + '<td>' + esc(r[5]) + '</td>'
392        + '<td>' + (r[6]||'<span style="color:#bbb">-</span>') + '</td>'
393        + '<td>' + esc(r[7]) + '</td>'
394        + '<td>' + (r[8]||'<span style="color:#bbb">-</span>') + '</td>'
395        + '<td><span class="badge badge-' + r[1] + '">' + r[1] + '</span></td>'
396        + '<td style="color:' + r[10] + '">' + r[9] + '</td></tr>';
397   }}
398   document.getElementById('tBody').innerHTML = h;
399   document.getElementById('rowCnt').textContent = filteredData.length.toLocaleString() + ' rows';
400   var hint = document.getElementById('pageHint');
401   if (filteredData.length > PAGE_SIZE) {{
402     hint.textContent = 'Showing first ' + PAGE_SIZE.toLocaleString() + ' of ' + filteredData.length.toLocaleString() + ' — refine search to see fewer';
403     hint.style.display = '';
404   }} else {{ hint.style.display = 'none'; }}
405   var noRows = document.getElementById('noRows');
406   if (filteredData.length === 0) {{
407     noRows.textContent = DATA.length === 0
408       ? 'No features extracted yet. Process a map first.'
409       : 'No matching features found.';
410     noRows.style.display = '';
411   }} else {{ noRows.style.display = 'none'; }}
412 }}
413 
414 /* ── Filters ──────────────────────────────────────────────────────── */
415 function applyFilters() {{
416   var search  = (document.getElementById('search').value || '').toLowerCase().trim();
417   var typeVal = document.getElementById('typeFilter').value;
418   var checked = new Set(getChecked());
419   filteredData = DATA.filter(function(r) {{
420     if (!checked.has(r[0])) return false;
421     if (typeVal && r[1] !== typeVal) return false;
422     if (search  && r[3].indexOf(search) === -1) return false;
423     return true;
424   }});
425   renderTable();
426 }}
427 
428 function onToggle() {{
429   var n = getChecked().length;
430   var btn  = document.getElementById('cmpBtn');
431   var hint = document.getElementById('cmpHint');
432   if (btn)  btn.disabled = n < 2;
433   if (hint) hint.textContent = n < 2 ? 'Check 2+ maps to compare' : n + ' maps selected \u2014 click Compare';
434   applyFilters();
435 }}
436 
437 function setAll(v) {{
438   document.querySelectorAll('.map-cb').forEach(function(cb) {{ cb.checked = v; }});
439   onToggle();
440 }}
441 
442 function clearFilters() {{
443   document.getElementById('search').value = '';
444   document.getElementById('typeFilter').value = '';
445   applyFilters();
446 }}
447 
448 function downloadCSV() {{
449   var lines = ['\uFEFF"Extracted Text","Grid Number","Map Number","Map Name","Year","Feature Type","Confidence"'];
450   filteredData.forEach(function(r) {{
451     lines.push(
452       '"' + r[4].replace(/"/g,'""') + '",'
453       + '"' + (r[5]||'').replace(/"/g,'""') + '",'
454       + '"' + (r[6]||'').replace(/"/g,'""') + '",'
455       + '"' + (r[7]||'').replace(/"/g,'""') + '",'
456       + '"' + (r[8]||'').replace(/"/g,'""') + '",'
457       + '"' + r[1] + '",'
458       + '"' + r[9] + '"'
459     );
460   }});
461   var blob = new Blob([lines.join('\\n')], {{type:'text/csv;charset=utf-8;'}});
462   var url = URL.createObjectURL(blob);
463   var a = document.createElement('a'); a.href = url; a.download = 'toposheet_features.csv'; a.click();
464   URL.revokeObjectURL(url);
465 }}
466 
467 function deleteSelected() {{
468   var keys = getChecked();
469   if (keys.length === 0) {{ alert('No maps selected.'); return; }}
470   var names = keys.slice(0,5).join('\\n') + (keys.length > 5 ? '\\n... and ' + (keys.length-5) + ' more' : '');
471   if (!confirm('Permanently delete ' + keys.length + ' map(s) and ALL their data?\\n\\n' + names)) return;
472   var keySet = new Set(keys.map(function(k) {{ return k.trim(); }}));
473   function removeDom() {{
474     for (var i = DATA.length - 1; i >= 0; i--) {{ if (keySet.has(DATA[i][0].trim())) DATA.splice(i,1); }}
475     keys.forEach(function(mk) {{
476       document.querySelectorAll('.map-cb').forEach(function(cb) {{ if (cb.value === mk) cb.closest('label').remove(); }});
477     }});
478     onToggle();
479   }}
480   fetch('http://localhost:5000/delete_maps', {{
481     method:'POST', headers:{{'Content-Type':'application/json'}},
482     body: JSON.stringify({{maps:keys}})
483   }})
484   .then(function(r) {{ return r.json(); }})
485   .then(function(d) {{
486     if (d.ok) {{ removeDom(); alert('\u2714 Deleted ' + keys.length + ' map(s).'); }}
487     else {{ alert('Error: ' + (d.error||'Unknown')); }}
488   }})
489   .catch(function() {{ removeDom(); alert('Removed from view.\\nOpen via http://localhost:5000/results to persist.'); }});
490 }}
491 
492 /* ── Compare (works on full DATA array — no DOM scanning) ─────────── */
493 function runCompare() {{
494   var maps = getChecked().map(function(m) {{ return m.trim(); }});
495   if (maps.length < 2) {{ alert('Please select at least 2 maps to compare.'); return; }}
496   try {{
497   var mapSet = new Set(maps);
498   var data = {{}};
499   maps.forEach(function(mk) {{ data[mk] = {{ names: new Set(), rows:[] }}; }});
500   DATA.forEach(function(r) {{
501     var mk = r[0].trim();
502     if (mapSet.has(mk)) {{ if (r[2]) data[mk].names.add(r[2]); data[mk].rows.push(r); }}
503   }});
504   var common = null;
505   maps.forEach(function(mk) {{
506     if (common === null) {{ common = new Set(data[mk].names); }}
507     else {{ var x = new Set(); common.forEach(function(n) {{ if (data[mk].names.has(n)) x.add(n); }}); common = x; }}
508   }});
509   var unique = {{}};
510   maps.forEach(function(mk) {{
511     unique[mk] = new Set();
512     data[mk].names.forEach(function(n) {{ if (!common.has(n)) unique[mk].add(n); }});
513   }});
514   var sumHTML = '<div class="cp-stat common"><div class="csn">' + common.size + '</div><div class="csl">Common Features</div></div>';
515   maps.forEach(function(mk) {{ sumHTML += '<div class="cp-stat uniq"><div class="csn">' + unique[mk].size + '</div><div class="csl">Only in ' + esc(mk) + '</div></div>'; }});
516   document.getElementById('cpSummary').innerHTML = sumHTML;
517   var tabsHTML = '<div class="cp-tab active" data-sec="sec-common">&#10003; Common (' + common.size + ')</div>';
518   maps.forEach(function(mk) {{ var sid='sec-u-'+mk.replace(/[^a-z0-9]/gi,'-'); tabsHTML += '<div class="cp-tab" data-sec="'+sid+'">Only: '+esc(mk)+' ('+unique[mk].size+')</div>'; }});
519   document.getElementById('cpTabs').innerHTML = tabsHTML;
520   document.getElementById('cpTabs').querySelectorAll('.cp-tab').forEach(function(tab) {{ tab.addEventListener('click', function() {{ showTab(this, this.dataset.sec); }}); }});
521   var bodyHTML = '<div class="cp-sec active" id="sec-common"><h3>Features in ALL '+maps.length+' maps \u2014 '+common.size+' common</h3>';
522   if (common.size===0) {{ bodyHTML += '<div class="empty-msg">No common features.</div>'; }}
523   else {{
524     bodyHTML += '<table class="cp-tbl"><thead><tr><th>Feature Name</th><th>In Maps</th></tr></thead><tbody>';
525     Array.from(common).sort().forEach(function(fn) {{ var ml=maps.filter(function(mk){{return data[mk].names.has(fn);}}).join(', '); bodyHTML+='<tr class="row-common"><td><strong>'+esc(fn)+'</strong></td><td>'+esc(ml)+'</td></tr>'; }});
526     bodyHTML += '</tbody></table>';
527   }}
528   bodyHTML += '</div>';
529   maps.forEach(function(mk) {{
530     var sid='sec-u-'+mk.replace(/[^a-z0-9]/gi,'-');
531     bodyHTML += '<div class="cp-sec" id="'+sid+'"><h3>Only in <em>'+esc(mk)+'</em> ('+unique[mk].size+')</h3>';
532     if (unique[mk].size===0) {{ bodyHTML+='<div class="empty-msg">Every feature also appears in other maps.</div>'; }}
533     else {{
534       bodyHTML += '<table class="cp-tbl"><thead><tr><th>Feature Name</th><th>Grid</th><th>Type</th><th>Conf</th></tr></thead><tbody>';
535       data[mk].rows.forEach(function(r) {{ if (!unique[mk].has(r[2])) return; bodyHTML+='<tr class="row-unique"><td><strong>'+esc(r[4])+'</strong></td><td>'+esc(r[5])+'</td><td>'+r[1]+'</td><td>'+r[9]+'</td></tr>'; }});
536       bodyHTML += '</tbody></table>';
537     }}
538     bodyHTML += '</div>';
539   }});
540   document.getElementById('cpBody').innerHTML = bodyHTML;
541   document.getElementById('cpTag').textContent = 'Comparing '+maps.length+' maps';
542   document.getElementById('mainView').style.display = 'none';
543   document.getElementById('cmpPanel').style.display = 'flex';
544   }} catch(err) {{ alert('Compare error: '+err.message); }}
545 }}
