548   document.getElementById('cmpPanel').style.display = 'none';
549   document.getElementById('mainView').style.display = 'flex';
550 }}
551 function showTab(el, secId) {{
552   document.querySelectorAll('.cp-tab').forEach(function(t) {{ t.classList.remove('active'); }});
553   el.classList.add('active');
554   document.querySelectorAll('.cp-sec').forEach(function(s) {{ s.classList.remove('active'); }});
555   var sec = document.getElementById(secId); if (sec) sec.classList.add('active');
556 }}
557 /* init */
558 filteredData = DATA.slice();
559 renderTable();
560 (function() {{
561   var _n = document.querySelectorAll('.map-cb').length;
562   var _btn = document.getElementById('cmpBtn');
563   var _hint = document.getElementById('cmpHint');
564   if (_btn)  _btn.disabled  = _n < 2;
565   if (_hint) _hint.textContent = _n >= 2 ? _n + ' maps selected \u2014 click Compare' : 'Check 2+ maps to compare';
566 }})();
567 </script>
